using System.Runtime.InteropServices;

namespace Compression;

internal static partial class NativeCompression
{
    [LibraryImport("compresslib")]
    [UnmanagedCallConv(CallConvs = [typeof(System.Runtime.CompilerServices.CallConvCdecl)])]
    internal static partial int compress_buffer(
        ref readonly byte input,
        nuint input_len,
        ref byte output,
        nuint output_len,
        out nuint bytes_written);

    internal static int CompressBuffer(ReadOnlySpan<byte> input, Span<byte> output, out nuint bytesWritten)
    {
        ref readonly byte inRef = ref MemoryMarshal.GetReference(input);
        ref byte outRef = ref MemoryMarshal.GetReference(output);
        return compress_buffer(ref inRef, (nuint)input.Length, ref outRef, (nuint)output.Length, out bytesWritten);
    }
}

